INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.15.99','cb','cb.adi.15','ЧБ Ади 15.99',99,'লক্ষেশ্বরো দেখিয়াছি এই নবদ্বীপে ।
হেন অধিবাস নাহি করে কারো বাপে ॥৯৯॥','лакш̣еш́вар о декхийа̄чхи эи навадвӣпе
хӣна адхива̄са на̄хи каре ка̄’ро ба̄пе',NULL,NULL),('cb.adi.15.100','cb','cb.adi.15','ЧБ Ади 15.100',100,'এমত চন্দন, মালা, দিব্য গুয়া-পান ।
অকাতরে কেহ কভু নাহি করে’ দান” ॥১০০॥','э-мата чандана, ма̄ла̄, дивйа гуйа̄-па̄на
ака̄таре кеха кабху на̄хи каре’ да̄на’',NULL,NULL),('cb.adi.15.101','cb','cb.adi.15','ЧБ Ади 15.101',101,'তবে রাজপণ্ডিত আনন্দ-চিত্ত হৈয়া ।
আইলেন অধিবাস-সামগ্রী লইয়া ॥১০১॥','табе ра̄джа-пан̣д̣ита а̄нанда читта хаийа̄
а̄илена адхива̄са-са̄магрӣ лаийа̄',NULL,NULL),('cb.adi.15.102','cb','cb.adi.15','ЧБ Ади 15.102',102,'বিপ্রবর্গ আপ্তবর্গ করি’ নিজ-সঙ্গে ।
বহুবিধ বাদ্য নৃত্য-গীত-মহারঙ্গে ॥১০২॥','випра-варга а̄пта-варга кари’ ниджа-сан̇ге
баху-видха ва̄дйа нр̣тйа-гӣта-маха̄ран̇ге',NULL,NULL),('cb.adi.15.103','cb','cb.adi.15','ЧБ Ади 15.103',103,'বেদবিধিপূর্ব্বক পরম-হর্ষ-মনে ।
ঈশ্বরের গন্ধ-স্পর্শ কৈলা শুভক্ষণে ॥১০৩॥','веда-видхи-пӯрвака парама-харш̣а-мане
ӣш́варера гандха-спарш́а каила̄ ш́убха-кш̣ан̣е',NULL,NULL),('cb.adi.15.104','cb','cb.adi.15','ЧБ Ади 15.104',104,'ততক্ষণে মহা-জয়জয়-হরি ধ্বনি ।
করিতে লাগিলা সবে মহা-স্তুতি-বাণী ॥১০৪॥','тата-кш̣ан̣е маха̄-джайа хари дхвани
карите ла̄гила̄ сабе маха̄-стути-ва̄н̣ӣ',NULL,NULL),('cb.adi.15.105','cb','cb.adi.15','ЧБ Ади 15.105',105,'পতিব্রতাগণে দেয় জয়জয়কার ।
বাদ্য-গীতে হৈল মহানন্দ অবতার ॥১০৫॥','пати-врата̄-ган̣е дейа джайа-джайака̄ра
ва̄дйа-гӣте хаила маха̄нанда-авата̄ра',NULL,NULL),('cb.adi.15.106','cb','cb.adi.15','ЧБ Ади 15.106',106,'হেন মতে করি’ অধিবাস শুভ-কায ।
গৃহে চলিলেন সনাতন-বিপ্ররাজ ॥১০৬॥','хӣна-мате кари’ адхива̄са ш́убха-ка̄йа
гр̣хе чалилена сана̄тана-випра-ра̄джа',NULL,NULL),('cb.adi.15.107','cb','cb.adi.15','ЧБ Ади 15.107',107,'এইমতে গিয়া ঈশ্বরের আপ্তগণে ।
লক্ষ্মীরে করিলা অধিবাস শুভ-ক্ষণে ॥১০৭॥','эи-мате гийа̄ ӣш́варера а̄пта-ган̣е
лакш̣мӣре карила̄ адхива̄са ш́убха-кш̣ан̣е',NULL,NULL),('cb.adi.15.108','cb','cb.adi.15','ЧБ Ади 15.108',108,'আর যত কিছু লোকে ‘লোকাচার’ বলে ।
দোঁহারাই সব করিলেন কুতূহলে ॥১০৮॥','а̄ра йата кичху локе ‘лока̄ча̄ра’ бале
дон̇ха̄ра̄и саба карилена кутухале',NULL,NULL),('cb.adi.15.109','cb','cb.adi.15','ЧБ Ади 15.109',109,'তবে সুপ্রভাতে প্রভু করি’ গঙ্গা-স্নান ।
আগে বিষ্ণু পূজি’ গৌরচন্দ্র ভগবান্ ॥১০৯॥','табе супрабха̄те прабху кари’ ган̇га̄-сна̄на
а̄ге виш̣н̣у пӯджи’ гаурачандра бхагава̄н',NULL,NULL),('cb.adi.15.110','cb','cb.adi.15','ЧБ Ади 15.110',110,'তবে শেষে সর্ব্ব-আপ্তগণের সহিতে ।
বসিলেন নান্দীমুখ-কর্ম্মাদি করিতে ॥১১০॥','табе ш́еш̣е сарва-а̄пта-ган̣ера сахите
василена на̄ндӣмукха-карма̄ди карите',NULL,NULL),('cb.adi.15.111','cb','cb.adi.15','ЧБ Ади 15.111',111,'বাদ্য-নৃত্য-গীতে হৈল মহা-কোলাহল ।
চতুর্দ্দিকে জয়জয় উঠিল মঙ্গল ॥১১১॥','ва̄дйа-нр̣тйа-гӣте хаила маха̄-кола̄хала
чатур-дике джайа-джайа ут̣хила ман̇гала',NULL,NULL),('cb.adi.15.112','cb','cb.adi.15','ЧБ Ади 15.112',112,'পূর্ণ-ঘট, ধান্য, দধি, দীপ, আম্র-সার ।
স্থাপিলেন ঘরে দ্বারে অঙ্গনে অপার ॥১১২॥','пӯрн̣а-гха̄т̣а, дха̄нйа, дадхи, дӣпа, а̄мра-са̄ра
стха̄пилена гхаре два̄ре ан̇гане апа̄ра',NULL,NULL),('cb.adi.15.113','cb','cb.adi.15','ЧБ Ади 15.113',113,'চতুর্দ্দিকে নানা-বর্ণে উড়য়ে পতাকা ।
কদলী রোপিয়া বান্ধিলেন আম্র-শাখা ॥১১৩॥','чатур-дике на̄на̄-варн̣е уд̣айе пата̄ка̄
кадалӣ ропийа̄ ба̄ндхилена а̄мра-ш́а̄кха̄',NULL,NULL),('cb.adi.15.114','cb','cb.adi.15','ЧБ Ади 15.114',114,'তবে আই পতিব্রতাগণ লই’ সঙ্গে ।
লোকাচার করিতে লাগিলা মহা-রঙ্গে ॥১১৪॥','табе а̄и пати-врата̄-ган̣а лаи’ сан̇ге
лока̄ча̄ра карите ла̄гила̄ маха̄-ран̇ге',NULL,NULL),('cb.adi.15.115','cb','cb.adi.15','ЧБ Ади 15.115',115,'আগে গঙ্গা পূজিয়া পরম-হর্ষ-মনে ।
তবে বাদ্য-বাজনে গেলেন ষষ্ঠী-স্থানে ॥১১৫॥','а̄ге ган̇га̄ пӯджийа̄ парама-харш̣а-мане
табе ва̄дйа-ба̄джане гелена ш̣аш̣т̣хӣ-стха̄не',NULL,NULL),('cb.adi.15.116','cb','cb.adi.15','ЧБ Ади 15.116',116,'ষষ্ঠী পূজি’ তবে বন্ধু-মন্দিরে-মন্দিরে ।
লোকাচার করিয়া আইলা নিজ-ঘরে ॥১১৬॥','ш̣аш̣т̣хӣ пӯджи’ табе бандху мандире мандире
лока̄ча̄ра карийа̄ а̄ила̄ ниджа-гхаре',NULL,NULL),('cb.adi.15.117','cb','cb.adi.15','ЧБ Ади 15.117',117,'তবে খই, কলা, তৈল, তাম্বূল, সিন্দূরে ।
দিয়া দিয়া পূর্ণ করিলেন স্ত্রীগণেরে ॥১১৭॥','табе кхаи, кала̄, таила, та̄мбӯла, синдӯре
дийа̄ дийа̄ пӯрн̣а карилена стрӣ-ган̣ере',NULL,NULL),('cb.adi.15.118','cb','cb.adi.15','ЧБ Ади 15.118',118,'ঈশ্বর-প্রভাবে দ্রব্য হৈল অসংখ্যাত ।
শচীও সবারে দেন বার পাঁচ-সাত ॥১১৮॥','ӣш́вара-прабха̄ве дравйа хаила асан̇кхйа̄та
ш́ачӣ о саба̄ре дена ба̄ра па̄н̃ча са̄та',NULL,NULL),('cb.adi.15.119','cb','cb.adi.15','ЧБ Ади 15.119',119,'তৈলে স্নান করিলেন সর্ব্ব-নারীগণে ।
হেন নাহি পরিপূর্ণ নহিল যে মনে ॥১১৯॥','таиле сна̄на карилена сарва-на̄рӣ-ган̣е
хӣна на̄хи парипӯрн̣а нахила йе мане',NULL,NULL),('cb.adi.15.120','cb','cb.adi.15','ЧБ Ади 15.120',120,'এইমত মহানন্দ লক্ষ্মীর ভবনে ।
লক্ষ্মীর জননী করিলেন হর্ষ মনে ॥১২০॥','эи-мата маха̄нанда лакш̣мӣра бхаване
лакш̣мӣра джанане карилена харш̣а мане',NULL,NULL),('cb.adi.15.121','cb','cb.adi.15','ЧБ Ади 15.121',121,'শ্রীরাজপণ্ডিত অতি চিত্তের উল্লাসে ।
সর্ব্বস্ব নিক্ষেপ করি’ মহানন্দে ভাসে ॥১২১॥','ш́рӣ-ра̄джа-пан̣д̣ита ати читтера улла̄се
сарвасва никш̣епа кари’ маха̄нанде бха̄се',NULL,NULL),('cb.adi.15.122','cb','cb.adi.15','ЧБ Ади 15.122',122,'সর্ব্ব-বিধিকর্ম্ম করি’ শ্রীগৌরসুন্দর ।
বসিলেন খানিক হইয়া অবসর ॥১২২॥','сарва-видхи-карма кари’ ш́рӣ-гаурасундара
василена кха̄ника хаийа̄ авасара',NULL,NULL),('cb.adi.15.123','cb','cb.adi.15','ЧБ Ади 15.123',123,'তবে সব-ব্রাহ্মণেরে ভোজ্য-বস্ত্র দিয়া ।
করিলেন সন্তোষ পরম-নম্র হৈয়া ॥১২৩॥','табе саба-бра̄хман̣ере бходжйа-вастра дийа̄
карилена сантош̣а парама-намра хаийа̄',NULL,NULL),('cb.adi.15.124','cb','cb.adi.15','ЧБ Ади 15.124',124,'যে যেমত পাত্র, যার যোগ্য যেন দান ।
সেইমত করিলেন সবারে সম্মান ॥১২৪॥','йе йе-мата па̄тра, йа̄’ра йогйа йена да̄на
сеи-мата карилена саба̄ре сама̄на',NULL,NULL),('cb.adi.15.125','cb','cb.adi.15','ЧБ Ади 15.125',125,'মহা-প্রীতে আশীর্ব্বাদ করি’ বিপ্রগণ ।
গৃহে চলিলেন সবে করিতে ভোজন ॥১২৫॥','маха̄-прӣте а̄ш́ӣрва̄да кари’ випра-ган̣а
гр̣хе чалилена сабе карите бходжана',NULL,NULL),('cb.adi.15.126','cb','cb.adi.15','ЧБ Ади 15.126',126,'অপরাহ্ণ বেলা আসি’ লাগিল হইতে ।
সবাই প্রভুর বেশ লাগিলা করিতে ॥১২৬॥','апара̄хна вела̄ а̄си’ ла̄гила хаите
саба̄и прабхура веш́а ла̄гила карите',NULL,NULL),('cb.adi.15.127','cb','cb.adi.15','ЧБ Ади 15.127',127,'চন্দনে লেপিত করি’ সকল শ্রীঅঙ্গ ।
মধ্যে মধ্যে সর্ব্বত্র দিলেন তথি গন্ধ ॥১২৭॥','чандане лепита кари’ сакала ш́рӣ-ан̇га',NULL,NULL),('cb.adi.15.128','cb','cb.adi.15','ЧБ Ади 15.128',128,'অর্দ্ধচন্দ্রাকৃতি করি’ ললাটে চন্দন ।
তথি-মধ্যে গন্ধের তিলক সুশোভন ॥১২৮॥','ардха-чандра̄кр̣ти кари’ лала̄т̣е чандана
татхи-мадхйе гандхӣра тилака суш́обхана',NULL,NULL),('cb.adi.15.129','cb','cb.adi.15','ЧБ Ади 15.129',129,'অদ্ভুত মুকুট শোভে শ্রীশির-উপর ।
সুগন্ধিমালায় পূর্ণ হৈল কলেবর ॥১২৯॥','адбхута мукут̣а ш́обхе ш́рӣ-ш́ира-упара
сугандхи-ма̄ла̄йа пӯрн̣а хаила калевара',NULL,NULL),('cb.adi.15.130','cb','cb.adi.15','ЧБ Ади 15.130',130,'দিব্য সূক্ষ্মপীতবস্ত্র, ত্রিকচ্ছ-বিধানে ।
পরাইয়া কজ্জল দিলেন শ্রীনয়নে ॥১৩০॥','дивйа сӯкш̣ма-пӣта-вастра, трикаччха-видха̄не
пара̄ийа̄ каджджала дилена ш́рӣ-найане',NULL,NULL),('cb.adi.15.131','cb','cb.adi.15','ЧБ Ади 15.131',131,'ধান্য, দূর্ব্বা, সূত্র করে করিয়া বন্ধন ।
ধরিতে দিলেন রম্ভা মঞ্জরী দর্পণ ॥১৩১॥','дха̄нйа, дӯрва̄, сӯтра каре карийа̄ бандхана
дхарите дилена рамбха̄ ман̃джарӣ дарпан̣а',NULL,NULL),('cb.adi.15.132','cb','cb.adi.15','ЧБ Ади 15.132',132,'সুবর্ণকুল দুই শ্রুতিমূলে দোলে ।
নানা-রত্ন-হার বান্ধিলেন বাহু-মূলে ॥১৩২॥','суварн̣а-кун̣д̣ала дуи ш́рути-мӯле доле
на̄на̄-ратна-ха̄ра ба̄ндхилена ба̄ху-мӯле',NULL,NULL),('cb.adi.15.133','cb','cb.adi.15','ЧБ Ади 15.133',133,'এইমত যে-যে-শোভা করে যে-যে-অঙ্গে ।
সকল ঘটনা সবে করিলেন রঙ্গে ॥১৩৩॥','эи-мате йе-йе ш́обха̄ каре йе-йе ан̇ге
сакала гхат̣ана̄ сабе карилена ран̇ге',NULL,NULL),('cb.adi.15.134','cb','cb.adi.15','ЧБ Ади 15.134',134,'ঈশ্বরের মূর্ত্তি দেখি’ যত নর-নারী ।
মুগ্ধ হইলেন সবে আপনা’ পাসরি’ ॥১৩৪॥','ӣш́варера мӯрти декхи’ йата нара-на̄рӣ
мугдха хаилена сабе а̄пана’ па̄ш́ари’',NULL,NULL),('cb.adi.15.135','cb','cb.adi.15','ЧБ Ади 15.135',135,'প্রহরেক বেলা আছে, হেনই সময় ।
সবেই বলেন,—“শুভ করাহ বিজয় ॥১৩৫॥','прахарека вела̄ а̄чхе, хӣнаи самайа
сабеи балена, — ‘ш́убха кара̄ха виджайа',NULL,NULL),('cb.adi.15.136','cb','cb.adi.15','ЧБ Ади 15.136',136,'প্রহরেক সর্ব্ব-নবদ্বীপে বেড়াইয়া ।
কন্যা-গৃহে যাইবেন গোধূলি করিয়া” ॥১৩৬॥','прахарека сарва-навадвӣпе бед̣а̄ийа̄
канйа̄-гр̣хе йа̄ибена годхӯли карийа̄’',NULL,NULL),('cb.adi.15.137','cb','cb.adi.15','ЧБ Ади 15.137',137,'তবে দিব্য দোলা করি’ বুদ্ধিমন্ত-খান ।
হরিষে আনিয়া করিলেন উপস্থান ॥১৩৭॥','табе дивйа дола̄ кари буддхиманта-кха̄на
хариш̣е а̄нийа̄ карилена упастха̄на',NULL,NULL),('cb.adi.15.138','cb','cb.adi.15','ЧБ Ади 15.138',138,'বাদ্য-গীতে উঠিল পরম কোলাহল ।
বিপ্রগণে করে বেদধ্বনি সুমঙ্গল ॥১৩৮॥','ва̄дйа-гӣте ут̣хила парама кола̄хала
